VALUES (12, 'Nonbor - Oshxona Avtomatlashtirish', 'Nonbor - Автоматизация общепита', 'Nonbor - Catering Automation', '<ol><li><span style="font-weight: bold;">Restoran</span>,</li><li>kafe va oshxonalar<a href="https://oiko">https://oiko</a></li><li>uchun to''liq avtomatlashtirish tizimi. <a href="https://nonbor.uz">Buyurtmalarni</a> qabul qilish, oshxona boshqaruvi, hisobotlar va moliyaviy <span style="background-color: rgb(254, 240, 138);">nazorat</span>.</li></ol>', 'Полная система автоматизации для ресторанов, кафе и столовых. Приём заказов, управление кухней, отчёты и финансовый контроль.', 'Complete automation system for restaurants, cafes and canteens. Order management, kitchen control, reports and financial monitoring.', 'Biznes va Avtomatlashtirish', 'CRM tizimlari', '["Python", "FastAPI", "PostgreSQL", "React", "WebSocket"]'::jsonb, '[{"uz": "Onlayn buyurtma qabul qilish", "ru": "Онлайн приём заказов", "en": "Online order acceptance"}, {"uz": "Real-time oshxona monitoring", "ru": "Мониторинг кухни в реальном времени", "en": "Real-time kitchen monitoring"}, {"uz": "Moliyaviy hisobotlar", "ru": "Финансовая отчётность", "en": "Financial reports"}, {"uz": "Inventar nazorati", "ru": "Контроль инвентаря", "en": "Inventory control"}, {"uz": "Xodimlar boshqaruvi", "ru": "Управление персоналом", "en": "Staff management"}]'::jsonb, '[]'::jsonb, 'from-[#00a6a6] to-[#00a6a6]/80', '/uploads/images/8109e63e-5b14-464b-a893-ad65398cd006.png', NULL, '[]'::jsonb, 'ACTIVE', true, false, 162, 0, '2025-12-26T12:24:45.054814+05:00')
