VALUES (11, '1C ERP - Korxona Yechimi', '1С ERP - Корпоративное решение', '1C ERP - Enterprise Solution', '1C ERP tizimi bilan to''liq integratsiya. Moliyaviy hisobotlar, buxgalteriya, ish haqi hisoblash va korxona resurslarini boshqarish.', 'Полная интеграция с системой 1С ERP. Финансовая отчётность, бухгалтерия, расчёт заработной платы и управление ресурсами предприятия.', 'Full integration with 1C ERP system. Financial reporting, accounting, payroll calculation and enterprise resource management.', 'Biznes va Avtomatlashtirish', 'ERP tizimlari', '["1C", "Python", "PostgreSQL", "REST API", "XML"]'::jsonb, '[{"uz": "Moliyaviy hisobotlar", "ru": "Финансовая отчётность", "en": "Financial reports"}, {"uz": "Inventar sinxronizatsiyasi", "ru": "Синхронизация инвентаря", "en": "Inventory synchronization"}, {"uz": "HR boshqaruvi", "ru": "Управление персоналом", "en": "HR management"}, {"uz": "Ish haqi tizimi", "ru": "Система расчёта зарплаты", "en": "Payroll system"}, {"uz": "Avtomatik hisobotlar", "ru": "Автоматические отчёты", "en": "Automated reports"}]'::jsonb, '["Telegram", "Email"]'::jsonb, 'from-primary-500 to-primary-600', 'https://images.unsplash.com/photo-1551288049-bebda4e38f71?w=800', NULL, '[]'::jsonb, 'ACTIVE', false, false, 35, 0, '2025-12-26T00:32:30.427179+05:00')
